async function getGithubUser(username) {
    if (!username) return null;
    return fetch(`https://api.github.com/users/${username}`, {
        next: {
            revalidate: 3600
        }
    }).then((res)=>{
        if (!res.ok) return null;
        return res.json();
    });
}
async function getGithubStats(username) {
    // Fetch user data
    const user = await getGithubUser(username);
    if (!user) return null;
    // Fetch all repos to calculate total stars/forks
    // Note: This only fetches first 100 public repos. For more, pagination is needed.
    const reposRes = await fetch(`https://api.github.com/users/${username}/repos?per_page=100`, {
        next: {
            revalidate: 3600
        }
    });
    const repos = await reposRes.json();
    // Fetch contributions data
    let totalContributions = 0;
    try {
        const contribRes = await fetch(`https://github-contributions-api.jogruber.de/v4/${username}`, {
            next: {
                revalidate: 3600
            }
        });
        if (contribRes.ok) {
            const contribData = await contribRes.json();
            // Sum up contributions from all years
            totalContributions = Object.values(contribData.total || {}).reduce((acc, curr)=>acc + (typeof curr === 'number' ? curr : 0), 0);
        }
    } catch (e) {
        console.error('Failed to fetch contributions:', e);
    }
    if (!Array.isArray(repos)) {
        return {
            followers: user.followers,
            public_repos: user.public_repos,
            total_stars: 0,
            total_forks: 0,
            total_contributions: totalContributions,
            username: user.login,
            profile_url: user.html_url
        };
    }
    const totalStars = repos.reduce((acc, repo)=>acc + repo.stargazers_count, 0);
    const totalForks = repos.reduce((acc, repo)=>acc + repo.forks_count, 0);
    return {
        followers: user.followers,
        public_repos: user.public_repos,
        total_stars: totalStars,
        total_forks: totalForks,
        total_contributions: totalContributions,
        username: user.login,
        profile_url: user.html_url
    };
}
